from collections.abc import Awaitable, Callable
from dataclasses import dataclass, field
from typing import Any

Handler = Callable[[Any, str], Awaitable[str | None]]


@dataclass(slots=True)
class Command:
    name: str
    handler: Handler
    description: str = ""
    hidden: bool = False  # dispatchable via get(), but omitted from listings (aliases)


@dataclass(slots=True)
class CommandRegistry:
    _cmds: dict[str, Command] = field(default_factory=dict)

    def register(
        self, name: str, *, description: str = "", hidden: bool = False
    ) -> Callable[[Handler], Handler]:
        def deco(fn: Handler) -> Handler:
            self._cmds[name] = Command(
                name=name, handler=fn, description=description, hidden=hidden
            )
            return fn

        return deco

    def get(self, name: str) -> Command | None:
        return self._cmds.get(name)

    def add_command(self, cmd: Command) -> None:
        self._cmds[cmd.name] = cmd

    def remove_command(self, name: str) -> None:
        self._cmds.pop(name, None)

    def all(self) -> list[Command]:
        # Hidden aliases stay dispatchable (via get) but out of the palette/help/completion.
        return sorted((c for c in self._cmds.values() if not c.hidden), key=lambda c: c.name)

    def help_text(self) -> str:
        width = max((len(c.name) for c in self._cmds.values()), default=4)
        lines = [f"  /{c.name.ljust(width)}  {c.description}".rstrip() for c in self.all()]
        return "Commands:\n" + "\n".join(lines)

from __future__ import annotations

import json
from pathlib import Path

GLOBAL_DIR = Path.home() / ".minima-harness"
PACKAGES_DIR = GLOBAL_DIR / "packages"

# Theme palette keys a theme JSON file may set.
_THEME_KEYS = ("user", "assistant", "tool", "warning", "muted", "accent")


def package_roots() -> list[Path]:
    """Installed package roots (``~/.minima-harness/packages/*/``)."""
    if not PACKAGES_DIR.is_dir():
        return []
    return [d for d in sorted(PACKAGES_DIR.iterdir()) if d.is_dir()]


def _theme_dirs(cwd: Path) -> list[Path]:
    return [GLOBAL_DIR / "themes", cwd / ".pi" / "themes", *(p / "themes" for p in package_roots())]


def _prompt_dirs(cwd: Path) -> list[Path]:
    return [
        GLOBAL_DIR / "prompts",
        cwd / ".pi" / "prompts",
        *(p / "prompts" for p in package_roots()),
    ]


def _skill_dirs(cwd: Path) -> list[Path]:
    # Agent Skills standard: ~/.agents/skills and .agents/skills (cwd); plus our dirs + packages.
    return [
        GLOBAL_DIR / "skills",
        Path.home() / ".agents" / "skills",
        cwd / ".agents" / "skills",
        cwd / ".pi" / "skills",
        *(p / "skills" for p in package_roots()),
    ]


def load_file_themes(cwd: Path) -> dict[str, dict[str, str]]:
    """Discover ``*.json`` theme files → {name: palette} (palettes keyed by _THEME_KEYS)."""
    out: dict[str, dict[str, str]] = {}
    for base in _theme_dirs(cwd):
        if not base.is_dir():
            continue
        for f in sorted(base.glob("*.json")):
            try:
                data = json.loads(f.read_text(encoding="utf-8"))
            except Exception:  # noqa: BLE001 - one bad file must not break themes
                continue
            if isinstance(data, dict):
                palette = {k: str(v) for k, v in data.items() if k in _THEME_KEYS}
                if palette:
                    out[f.stem] = palette
    return out


def load_templates(cwd: Path) -> dict[str, str]:
    """Discover ``*.md`` prompt templates → {name (stem): body}."""
    out: dict[str, str] = {}
    for base in _prompt_dirs(cwd):
        if not base.is_dir():
            continue
        for f in sorted(base.glob("*.md")):
            try:
                body = f.read_text(encoding="utf-8").strip()
            except Exception:  # noqa: BLE001
                continue
            if body:
                out[f.stem] = body
    return out


def load_skills(cwd: Path) -> dict[str, str]:
    """Discover ``<dir>/<name>/SKILL.md`` skill packages → {name: body}."""
    out: dict[str, str] = {}
    for base in _skill_dirs(cwd):
        if not base.is_dir():
            continue
        for d in sorted(base.iterdir()):
            if not d.is_dir():
                continue
            skill = d / "SKILL.md"
            if d.name in out or not skill.is_file():
                continue
            try:
                body = skill.read_text(encoding="utf-8").strip()
            except Exception:  # noqa: BLE001
                continue
            if body:
                out[d.name] = body
    return out

from __future__ import annotations

import time

from rich.text import Text
from textual.containers import ScrollableContainer
from textual.widgets import Static

from minima_harness.tui.theme import current_theme, get_theme

# Min seconds between live-stream repaints (~16 Hz). The terminal emulator repaints the whole
# chat region on each flush, so a tighter cadence (e.g. 0.03 = 33 Hz) drives terminal CPU/fans
# hard for no readability gain. 16 Hz still reads as smooth streaming.
THROTTLE_S = 0.06

_ROLE_COLOR = {"user": "user", "assistant": "assistant", "tool": "tool", "thinking": "muted"}
_ROLE_PREFIX = {
    "user": "▸ ",
    "assistant": "",
    "tool": "",
    "error": "✗ ",
    "system": "",
    "thinking": "thoughts  ",
}


def _color_for(role: str) -> str:
    t = get_theme(current_theme())
    return t.get(_ROLE_COLOR.get(role, "muted"), t["assistant"])


class MessageBubble(Static):
    """A single chat message. Appendable + throttled for live assistant streaming."""

    def __init__(
        self,
        role: str,
        text: str = "",
        *,
        prefix: str | None = None,
        color: str | None = None,
        italic: bool = False,
    ) -> None:
        self._role = role
        self._color_override = color
        self._color = color or _color_for(role)
        self._italic = italic
        self._prefix = prefix if prefix is not None else _ROLE_PREFIX.get(role, "")
        self._buf = text
        self._last_flush = 0.0
        self._markdown = False
        super().__init__(self._content_text())

    def _style(self) -> str:
        return f"italic {self._color}" if self._italic else self._color

    @property
    def buffer(self) -> str:
        return self._buf

    def append(self, delta: str) -> None:
        self._buf += delta
        if time.monotonic() - self._last_flush >= THROTTLE_S:
            self.flush()

    def set_text(self, text: str) -> None:
        self._buf = text
        self.flush()

    def flush(self) -> None:
        self._last_flush = time.monotonic()
        try:
            self.update(self._content_text())
        except Exception:  # noqa: BLE001 - not mounted / no active app; buffer stays current
            pass

    def render_markdown(self) -> None:
        """Swap the bubble's plain-streamed text for rendered Markdown (assistant finalize)."""
        from rich.markdown import Markdown

        self._markdown = True
        self._last_flush = time.monotonic()
        try:
            self.update(Markdown(self._buf))
        except Exception:  # noqa: BLE001 - fall back to plain text if markdown rendering fails
            self.flush()

    def refresh_theme(self) -> None:
        """Re-read the active palette and re-render (used after /theme)."""
        self._color = self._color_override or _color_for(self._role)
        if self._markdown:
            self.render_markdown()
        else:
            self.flush()

    def _content_text(self) -> Text:
        if self._role == "tool" and "\n" in self._buf:
            return self._tool_diff_text()
        return Text(f"{self._prefix}{self._buf}", style=self._style())

    def _tool_diff_text(self) -> Text:
        """Colorize a multi-line tool-call body like an IDE diff: + green, - red, @@ cyan."""
        t = Text()
        lines = f"{self._prefix}{self._buf}".split("\n")
        for i, line in enumerate(lines):
            body = line + ("" if i == len(lines) - 1 else "\n")
            s = line.lstrip()
            if s.startswith("+") and not s.startswith("+++"):
                t.append(body, style="green")
            elif s.startswith("-") and not s.startswith("---"):
